// Processar cada carga da API ATAK
const cargas = $input.all();
const crypto = require('crypto');
const results = [];

for (const item of cargas) {
  const carga = item.json;

  // Gerar hash para dedup
  const hashInput = [
    carga.numero_documento || '',
    carga.numero_pcr || '',
    carga.fornecedor_codigo || '',
    carga.data_coleta || ''
  ].join('|');
  const hash = crypto.createHash('sha256').update(hashInput).digest('hex');

  // Calcular total classificado
  const classA = parseInt(carga.class_a) || 0;
  const classB = parseInt(carga.class_b) || 0;
  const classC = parseInt(carga.class_c) || 0;
  const totalClassificado = parseInt(carga.total_classificado) || (classA + classB + classC);

  results.push({
    json: {
      atak_id: carga.id,
      numero_documento: carga.numero_documento,
      numero_pcr: carga.numero_pcr,
      numero_carga: carga.numero_carga,
      fornecedor_codigo: carga.fornecedor_codigo,
      fornecedor_nome: carga.fornecedor_nome,
      frigorifico: carga.frigorifico,
      motorista: carga.motorista,
      placa_veiculo: carga.placa_veiculo,
      transportadora: carga.transportadora,
      data_coleta: carga.data_coleta,
      data_chegada: carga.data_chegada,
      qtd_frigo: parseInt(carga.qtd_frigo) || 0,
      peso_frigo_kg: parseFloat(carga.peso_frigo_kg) || 0,
      produto: carga.produto,
      tipo_conservacao: carga.tipo_conservacao,
      class_a: classA,
      class_b: classB,
      class_c: classC,
      total_classificado: totalClassificado,
      hash_registro: hash,
      payload_json: carga
    }
  });
}

return results;

// Validar regras de negócio em cada carga inserida
const cargas = $input.all();
const divergencias = [];

for (const item of cargas) {
  const c = item.json;

  // REGRA 1: A + B + C deve bater com total
  const somaABC = (c.class_a || 0) + (c.class_b || 0) + (c.class_c || 0);
  if (c.total_classificado > 0 && somaABC !== c.total_classificado) {
    divergencias.push({
      json: {
        tipo_divergencia: 'abc_total_mismatch',
        gravidade: 'critica',
        tabela_origem: 'atak_cargas_raw',
        registro_origem_id: c.id,
        carga_id: c.id,
        fornecedor_codigo: c.fornecedor_codigo,
        numero_documento: c.numero_documento,
        campo_divergente: 'class_a+class_b+class_c',
        valor_esperado: String(c.total_classificado),
        valor_encontrado: String(somaABC),
        diferenca_abs: Math.abs(c.total_classificado - somaABC),
        mensagem: `A(${c.class_a}) + B(${c.class_b}) + C(${c.class_c}) = ${somaABC} ≠ Total(${c.total_classificado})`,
        detectado_por: 'n8n_automatico',
        n8n_execution_id: $execution.id
      }
    });
  }

  // REGRA 2: Verificar %C para fornecedor crítico
  if (c.total_classificado > 0) {
    const pctC = ((c.class_c || 0) / c.total_classificado) * 100;
    if (pctC > 15) {
      divergencias.push({
        json: {
          tipo_divergencia: 'fornecedor_critico',
          gravidade: pctC > 25 ? 'critica' : 'atencao',
          tabela_origem: 'atak_cargas_raw',
          registro_origem_id: c.id,
          carga_id: c.id,
          fornecedor_codigo: c.fornecedor_codigo,
          numero_documento: c.numero_documento,
          campo_divergente: 'pct_c',
          valor_esperado: '≤15%',
          valor_encontrado: pctC.toFixed(2) + '%',
          diferenca_abs: pctC - 15,
          mensagem: `Fornecedor ${c.fornecedor_nome || c.fornecedor_codigo}: %C = ${pctC.toFixed(1)}% (limite: 15%)`,
          detectado_por: 'n8n_automatico',
          n8n_execution_id: $execution.id
        }
      });
    }
  }
}

return divergencias.length > 0 ? divergencias : [{ json: { _skip: true } }];

// Gerar alerta para divergências críticas
const divs = $input.all();
const criticas = divs.filter(d => d.json.gravidade === 'critica');

if (criticas.length === 0) return [{ json: { _skip: true } }];

return criticas.map(d => ({
  json: {
    tipo: d.json.tipo_divergencia,
    gravidade: 'critica',
    status: 'aberto',
    frigorifico: d.json.fornecedor_codigo,
    numero_carga: d.json.numero_documento,
    mensagem: d.json.mensagem,
    acao_sugerida: d.json.tipo_divergencia === 'fornecedor_critico' 
      ? 'Bloquear recebimento do fornecedor até análise da qualidade'
      : 'Verificar recontagem e reconciliar dados com frigorífico',
    origem: 'n8n_integracao_atak',
    criado_por: 'n8n_automatico'
  }
}));

// Atualizar log de sync com resultado final
const items = $input.all();
const syncLogId = $('Criar Log de Sync').first().json.id;

const totalRegistros = $('Transformar Cargas').all().length;
const totalDivergencias = $('Validar Regras CQ').all().filter(d => !d.json._skip).length;

return [{
  json: {
    id: syncLogId,
    status: totalDivergencias > 0 ? 'parcial' : 'sucesso',
    total_registros: totalRegistros,
    novos: totalRegistros,
    erros: 0,
    fim: new Date().toISOString(),
    detalhes_json: {
      divergencias_encontradas: totalDivergencias,
      execution_id: $execution.id
    }
  }
}];
